    /**
     * Abstract base class for filtering record batches and individual records during log compaction.
     *
     * <p><b>Filtering Levels:</b>
     * <ol>
     *   <li>{@link #checkBatchRetention(RecordBatch)} — decides if an entire batch should be deleted
     *       without examining records. This is useful for optimizing deletion of large batches.</li>
     *   <li>{@link #shouldRetainRecord(RecordBatch, Record)} — decides if individual records
     *       should be retained (e.g., based on TTL, topic configuration, or record key).</li>
     * </ol>
     * </p>
     *
     * <p><b>Compaction Semantics:</b> The filter is called during log compaction to:
     * <ul>
     *   <li>Discard stale records (those with earlier versions of the same key)</li>
     *   <li>Enforce retention policies (delete records older than a TTL)</li>
     *   <li>Clean up tombstones and transaction markers</li>
     *   <li>Up-convert old message formats to the current version</li>
     * </ul>
     * </p>
     *
     * @see FilterResult
     */
    public abstract static class RecordFilter {
        /** The current time used for TTL calculations, in milliseconds since epoch. */
        public final long currentTime;
        /** The number of milliseconds to retain tombstones and transaction markers. */
        public final long deleteRetentionMs;

        /**
         * Construct a filter with the given time parameters.
         *
         * @param currentTime The current time in milliseconds since epoch
         * @param deleteRetentionMs The minimum duration to retain deletion markers
         */
        public RecordFilter(final long currentTime, final long deleteRetentionMs) {
            this.currentTime = currentTime;
            this.deleteRetentionMs = deleteRetentionMs;
        }

        /**
         * Result of batch-level retention check.
         */
        public static class BatchRetentionResult {
            /** The batch retention decision. */
            public final BatchRetention batchRetention;
            /** Whether this batch contains an end-of-transaction marker for an empty transaction. */
            public final boolean containsMarkerForEmptyTxn;

            /**
             * Construct a batch retention result.
             *
             * @param batchRetention The retention decision
             * @param containsMarkerForEmptyTxn Whether the batch contains an empty transaction marker
             */
            public BatchRetentionResult(final BatchRetention batchRetention,
                                        final boolean containsMarkerForEmptyTxn) {
                this.batchRetention = batchRetention;
                this.containsMarkerForEmptyTxn = containsMarkerForEmptyTxn;
            }
        }

        /**
         * Decision enum for batch-level retention.
         */
        public enum BatchRetention {
            /** Delete the batch entirely without inspecting records. */
            DELETE,
            /** Retain the batch even if it is empty. */
            RETAIN_EMPTY,
            /** Delete the batch only if it becomes empty after filtering. */
            DELETE_EMPTY
        }

        /**
         * Check whether the full batch can be discarded without inspecting individual records.
         *
         * <p><b>Optimization:</b> This method is called first and avoids iteration overhead for
         * batches that can be entirely discarded (e.g., all records are too old).</p>
         *
         * @param batch The {@link RecordBatch} to evaluate
         * @return A {@link BatchRetentionResult} indicating the decision
         */
        protected abstract BatchRetentionResult checkBatchRetention(RecordBatch batch);

        /**
         * Check whether a record should be retained in the log.
         *
         * <p><b>Invocation:</b> This method is called only for records in batches that were not
         * entirely discarded by {@link #checkBatchRetention(RecordBatch)}.</p>
         *
         * <p><b>Example Logic:</b> A real implementation might check:
         * <ul>
         *   <li>Record key uniqueness (keep only the latest version)</li>
         *   <li>Record age (discard records older than the log retention period)</li>
         *   <li>Tombstone retention (keep tombstones for a grace period to ensure eventual consistency)</li>
         * </ul>
         * </p>
         *
         * @param recordBatch The {@link RecordBatch} containing the record
         * @param record The {@link Record} to evaluate
         * @return {@code true} if the record should be kept, {@code false} if it should be discarded
         */
        protected abstract boolean shouldRetainRecord(RecordBatch recordBatch, Record record);
    }

    /**
     * Result of filtering a set of record batches.
     *
     * <p>This class summarizes the input/output metrics of the filtering operation,
     * useful for logging and monitoring compaction progress.</p>
     */
    public static class FilterResult {
        /** The output buffer containing filtered records. May be reallocated if insufficient capacity. */
        private ByteBuffer outputBuffer;
        /** Total number of records (messages) read during filtering. */
        private int messagesRead = 0;
        /** Total number of bytes read from input batches. */
        private int bytesRead = 0;
        /** Total number of records retained in the output. */
        private int messagesRetained = 0;
        /** Total number of bytes written to the output buffer. */
        private int bytesRetained = 0;
        /** The maximum offset of any retained record. */
        private long maxOffset = -1L;
        /** The maximum timestamp of any retained record. */
        private long maxTimestamp = RecordBatch.NO_TIMESTAMP;
        /** The offset of the record with the maximum timestamp (at a shallow level). */
        private long shallowOffsetOfMaxTimestamp = -1L;

        /**
         * Construct a filter result with the given output buffer.
         *
         * @param outputBuffer The {@link ByteBuffer} to accumulate filtered records in
         */
        private FilterResult(ByteBuffer outputBuffer) {
            this.outputBuffer = outputBuffer;
        }

        private void updateRetainedBatchMetadata(MutableRecordBatch retainedBatch, int numMessagesInBatch, boolean headerOnly) {
            int bytesRetained = headerOnly ? DefaultRecordBatch.RECORD_BATCH_OVERHEAD : retainedBatch.sizeInBytes();
            updateRetainedBatchMetadata(retainedBatch.maxTimestamp(), retainedBatch.lastOffset(),
                    retainedBatch.lastOffset(), numMessagesInBatch, bytesRetained);
        }

        private void updateRetainedBatchMetadata(long maxTimestamp, long shallowOffsetOfMaxTimestamp, long maxOffset,
                                                 int messagesRetained, int bytesRetained) {
            validateBatchMetadata(maxTimestamp, shallowOffsetOfMaxTimestamp, maxOffset);
            if (maxTimestamp > this.maxTimestamp) {
                this.maxTimestamp = maxTimestamp;
                this.shallowOffsetOfMaxTimestamp = shallowOffsetOfMaxTimestamp;
            }
            this.maxOffset = Math.max(maxOffset, this.maxOffset);
            this.messagesRetained += messagesRetained;
            this.bytesRetained += bytesRetained;
        }

        private void validateBatchMetadata(long maxTimestamp, long shallowOffsetOfMaxTimestamp, long maxOffset) {
            if (maxTimestamp != RecordBatch.NO_TIMESTAMP && shallowOffsetOfMaxTimestamp < 0)
                throw new IllegalArgumentException("shallowOffset undefined for maximum timestamp " + maxTimestamp);
            if (maxOffset < 0)
                throw new IllegalArgumentException("maxOffset undefined");
        }

        /**
         * Get the output buffer containing filtered records.
         *
         * @return The {@link ByteBuffer} with filtered records
         */
        public ByteBuffer outputBuffer() {
            return outputBuffer;
        }

        /**
         * Get the total number of records read during filtering.
         *
         * @return The count of input records examined
         */
        public int messagesRead() {
            return messagesRead;
        }

        /**
         * Get the total number of bytes read from input batches.
         *
         * @return The count of input bytes
         */
        public int bytesRead() {
            return bytesRead;
        }

        /**
         * Get the total number of records retained in the output.
         *
         * @return The count of output records
         */
        public int messagesRetained() {
            return messagesRetained;
        }

        /**
         * Get the total number of bytes written to the output buffer.
         *
         * @return The count of output bytes
         */
        public int bytesRetained() {
            return bytesRetained;
        }

        /**
         * Get the maximum offset of any retained record.
         *
         * @return The highest offset, or -1L if no records were retained
         */
        public long maxOffset() {
            return maxOffset;
        }

        /**
         * Get the maximum timestamp of any retained record.
         *
         * @return The highest timestamp value
         */
        public long maxTimestamp() {
            return maxTimestamp;
        }

        /**
         * Get the offset of the record with the maximum timestamp.
         *
         * @return The offset at the maximum timestamp, or -1L if none
         */
        public long shallowOffsetOfMaxTimestamp() {
            return shallowOffsetOfMaxTimestamp;
        }
    }

